#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=300005;
ll n,m,a[N],tr[N];
void update(ll x,ll y)
{
	for(int i=x;i<=n;i+=(i&(-i))) tr[i]+=y;
}
ll query(ll x)
{
	ll sum=0;
	for(int i=x;i>0;i-=(i&(-i))) sum+=tr[i];
	return sum;
}
set<int> st;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		update(i,a[i]);
		st.insert(i);
	}
	int tmp=n;
	while(tmp--)
	{
		ll op,l,r;
		cin>>op>>l>>r;
		if(l>r) swap(l,r);
		if(op==0)
		{
			auto it=st.lower_bound(l),it2=st.upper_bound(r);
			set<int> ::iterator itt;
			for(itt=it;itt!=it2;)
			{
				int num=*itt;
				update(num,-a[num]);
				a[num]=sqrt(a[num]);
				update(num,a[num]);
				itt++;
				if(a[num]<=1) st.erase(prev(itt));
			}
		}
		else cout<<query(r)-query(l-1)<<"\n";
	}
	return 0;
}
